arguments.command:
cd /app/varsea; f=disks/sub1/subA/subAlpha/ae3f4c.dat; python3 - <<'EOF'
data=open('/app/varsea/disks/sub1/subA/subAlpha/ae3f4c.dat','rb').read()
import re
for m in re.finditer(b'PK\x03\x04', data):
    print('local header at', m.start())
for m in re.finditer(b'PK\x01\x02', data):
    print('central dir at', m.start())
for m in re.finditer(b'PK\x05\x06', data):
    print('EOCD at', m.start())
# find launchcode occurrences
for m in re.finditer(b'launchcode', data):
    print('launchcode at', m.start(), data[m.start()-40:m.start()+60])
EOF

